record.field:
claimants_lines = record.partner_id.x_claimants_line_ids
for claimant_line in claimants_lines:   # One invoice per claimant
    for invoice in record.invoice_ids:
        new_invoice = invoice.copy({'partner_id': claimant_line.x_claimants_id.id})
        for orig_line, new_line in zip(invoice.invoice_line_ids, new_invoice.invoice_line_ids):
            if orig_line.product_id:
                new_line.write({'price_unit': new_line.price_unit / len(claimants_lines) if new_line.price_unit else 0.0})
        invoice.write({'state': 'cancel'})

FIELDS_TO_REMOVE = {'force_send', 'mail_auto_delete', 'model_description', 'force_email_lang'}
for wizard in records:
    wizard.partner_ids.write({'x_suggest_approval': wizard.x_approval})
    body_html = wizard.body
    res_ids = wizard._evaluate_res_ids()
    post_values_all = wizard._prepare_mail_values(res_ids)

    for res_id, post_values in post_values_all.items():
        for key in FIELDS_TO_REMOVE:
            post_values.pop(key, None)
        post_values.update({'body_html': body_html, 'x_approval_status': 'pending'})

        env['mail.mail'].sudo().create(post_values)
